#include "pump_peristaltic.h"
#include <Arduino.h>
#define PUMP_IN1 25
#define PUMP_IN2 26
#define PUMP_EN 27
void pump_setup(){pinMode(PUMP_IN1,OUTPUT);pinMode(PUMP_IN2,OUTPUT);ledcAttach(PUMP_EN,5000,8);Serial.println("[pump] OK");}
void pump_on(uint8_t p){digitalWrite(PUMP_IN1,HIGH);digitalWrite(PUMP_IN2,LOW);ledcWrite(PUMP_EN,map(p,0,100,0,255));}
void pump_off(){digitalWrite(PUMP_IN1,LOW);digitalWrite(PUMP_IN2,LOW);ledcWrite(PUMP_EN,0);}
void pump_dispense_ml(float ml,float rate){pump_on(100);delay((unsigned long)(ml/rate*60000));pump_off();}
